import json, re, pandas as pd

def load_records(var):
    if isinstance(var, str):
        with open(var, 'r') as f:
            return json.load(f)
    return var

biz = load_records(var_call_NFEvdMmwAZrZR9o392X4YuFv)
dfb = pd.DataFrame(biz)

pat = re.compile(r"\bin\s+[^,]+,\s*([A-Z]{2}),")
st = dfb['description'].astype(str).str.extract(pat, expand=False)

head = []
for x in st.head(20).tolist():
    if pd.isna(x):
        head.append(None)
    else:
        head.append(str(x))

out = {'dtype': str(st.dtype), 'head': head, 'non_null': int(st.notna().sum())}

print('__RESULT__:')
print(json.dumps(out))

